documentation.value:
Simple event/callback registration.

```lua
local listeners = {}
function on(event, fn)
    listeners[event] = listeners[event] or {}
    table.insert(listeners[event], fn)
end
function emit(event, ...)
    for _, fn in ipairs(listeners[event] or {}) do
        fn(...)
    end
end
```

